//-------------------------------------------------------------------------
//scwin.onpageload 후 UDC관련 처리
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {
  //공통코드 적용
  const codeOptions = [{
    grpCd: "OP117",
    compID: "gr_volRslts:shiftClsCd"
  },
  //GauceUtil.getGridCombo("FM015",false) 
  {
    grpCd: "SD060",
    compID: "gr_volRslts:impExpClsCd"
  }, {
    grpCd: "OP117",
    compID: "gr_shiftingRslts:shiftClsCd"
  }, {
    grpCd: "SD060",
    compID: "gr_shiftingRslts:impExpClsCd"
  }];
  $c.data.setCommonCode($p, codeOptions);
  $c.gus.setValidExp($p, gr_volRslts, scwin.gr_volRslts_validExp);
  $c.gus.setValidExp($p, gr_shiftingRslts, scwin.gr_shiftingRslts_validExp);

  //작업단계
  // ds_wkrStp.DataID = "/cm.zz.RetrieveComboCMD.do?sysCd=WrkStpEBC&queryId=retreiveWrkStpL4";
  dma_wkrStp.set("sysCd", "WrkStpEBC"); // ds_wkrStp -> dma_wkrStp
  dma_wkrStp.set("queryId", "retreiveWrkStpL4");
  await scwin.submitExcute(sbm_wkrStp);
  if (scwin.PcvsslMgntNo != "") {
    em_cvsslMgntNo.setValue(scwin.PcvsslMgntNo); // 본선관리번호		
    scwin.f_Retrieve();
  } else {
    scwin.f_DivHoldEachWorkPlanList(); // 본선작업계획상세조회 테이블 생성	 
    em_cvsslMgntNo.focus(); // on_load focus
  }

  // 속성 hidden 으로 제어가 안되어 스크립트로 숨겼음
  gr_volRslts.setColumnVisible("commCd", false);
  gr_volRslts.setColumnVisible("rsltsIndictNo", false);
  gr_volRslts.setColumnVisible("volSeq", false);
  gr_volRslts.setColumnVisible("rmk", false);
  gr_shiftingRslts.setColumnVisible("commCd", false);
  gr_shiftingRslts.setColumnVisible("rsltsIndictNo", false);
  gr_shiftingRslts.setColumnVisible("volSeq", false);
};

//-------------------------------------------------------------------------
// 조회 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  // 검색조건 필수 입력 체크
  let validVal = await $c.gus.cfValidate($p, [em_cvsslMgntNo]);
  if (!validVal) {
    return;
  }
  await scwin.submitExcute(sbm_search);
  await scwin.f_DivHoldEachWorkPlanList();
  await scwin.f_GridIOCheck3();
  scwin.chk_input = "F";
};
/**
 * @method 
 * @name submitdone 
 * @description submit 정상
 */
scwin.submitdone = async function (e) {
  let submitObj = $p.getComponentById(e.id);
  switch (submitObj) {
    case sbm_search:
      await scwin.sbm_search_submitdone(e);
      break;
    case sbm_wkrStp:
      await scwin.sbm_wkrStp_submitdone(e);
      break;
    case sbm_save:
      await scwin.sbm_save_submitdone(e);
      break;
    default:
      break;
  }
};

/**
 * @method 
 * @name submitExcute 
 * @description submit 처리
 */
scwin.submitExcute = async function (sbmObj) {
  const e = await $c.sbm.execute($p, sbmObj);
  if (e.responseJSON.resultDataSet[0].Msg == 'SUCC') {
    if (e.responseJSON.resultDataSet[0].Code == -1) return;
    await scwin.submitdone(e);
  }
  ;
};

//-------------------------------------------------------------------------
// 저장 버튼 클릭
//-------------------------------------------------------------------------
scwin.f_mainSave = async function () {
  let lobranCd = ds_main1.getCellData(0, "lobranCd");
  if (ds_volRslts.getModifiedIndex().length > 0 || ds_shiftingRslts.getModifiedIndex().length > 0) {
    let gridVal = await $c.gus.cfValidate($p, [gr_volRslts], null, true);
    if (!gridVal) return;
    if (ds_volRslts.getModifiedIndex().length > 0 && ds_volRslts.getRowStatusValue(ds_volRslts.rowPosition) != 3) {
      // 2 -> 3

      let cnt = ds_volRslts.getTotalRow();
      let wrkDt = "";
      let stHh = "";
      let endHh = "";
      let shift = "";
      for (let i = 0; i < cnt; i++) {
        let wrkDt = ds_volRslts.getCellData(i, "wrkDt");
        let stHh = gr_volRslts.getCellDisplayData(i, "wrkStHh").replace(":", "");
        let endHh = gr_volRslts.getCellDisplayData(i, "wrkEndHh").replace(":", "");

        // 화면에 보이는 값이 아닌 실제값
        let stHhReal = ds_volRslts.getCellData(i, "wrkStHh");
        let endHhReal = ds_volRslts.getCellData(i, "wrkEndHh");
        let shift = ds_volRslts.getCellData(i, "shiftClsCd");
        if (ds_volRslts.getRowStatusValue(i) == 2) {
          /* 1 : Insert*/ // 1 -> 2

          for (let j = 0; j < cnt; j++) {
            if (ds_volRslts.getCellData(i, "wrkDt") == ds_volRslts.getCellData(j, "wrkDt") && ds_volRslts.getCellData(i, "shiftClsCd") == ds_volRslts.getCellData(j, "shiftClsCd") && i != j) {
              await $c.gus.cfAlertMsg($p, i + "번째 작업일자와 Shift는 중복 데이터이므로 입력하실 수 없습니다.");
              ds_volRslts.rowPosition = i;
              return;
            }
          }
        }
        if (stHhReal.length != 4) {
          // stHh -> stHhReal
          await $c.gus.cfAlertMsg($p, MSG_CM_ERR_055, ["시간형식"]);
          // gr_volRslts.SetColumn("wrkStHh");
          gr_volRslts.setFocusedCell(ds_volRslts.getRowPosition(), "wrkStHh", false);
          gr_volRslts.focus();
          return false;
        }
        if (endHhReal.length != 4) {
          // endHh -> endHhReal
          await $c.gus.cfAlertMsg($p, MSG_CM_ERR_055, ["시간형식"]);
          gr_volRslts.setFocusedCell(ds_volRslts.getRowPosition(), 'wrkEndHh'); // gr_volRslts.SetColumn("wrkEndHh");
          gr_volRslts.focus();
          return false;
        }
        if (stHh.slice(0, 2) > "23") {
          await $c.gus.cfAlertMsg($p, MSG_CM_ERR_021, ["작업시간"]); // "@은(는) 시가 잘못되었습니다."
          gr_volRslts.setFocusedCell(ds_volRslts.getRowPosition(), 'wrkStHh');
          gr_volRslts.focus();
          return;
        }
        if (stHh.slice(2, 2) > "59") {
          await $c.gus.cfAlertMsg($p, MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
          gr_volRslts.setFocusedCell(ds_volRslts.getRowPosition(), 'wrkStHh');
          gr_volRslts.focus();
          return;
        }
        if (endHh.slice(0, 2) > "24") {
          await $c.gus.cfAlertMsg($p, MSG_CM_ERR_021, ["작업시간"]); // "@은(는) 시가 잘못되었습니다."
          gr_volRslts.setFocusedCell(ds_volRslts.getRowPosition(), 'wrkEndHh');
          gr_volRslts.focus();
          return;
        }
        if (endHh.slice(0, 2) == "00" && endHh.slice(2, 2) == "00") {
          await $c.gus.cfAlertMsg($p, MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
          gr_volRslts.setFocusedCell(ds_volRslts.getRowPosition(), 'wrkEndHh');
          gr_volRslts.focus();
          return;
        }
        if (endHh.slice(0, 2) == "24" && endHh.slice(2, 2) > "00") {
          await $c.gus.cfAlertMsg($p, MSG_CM_ERR_021, ["작업시간"]); // "@은(는) 시가 잘못되었습니다."
          gr_volRslts.setFocusedCell(ds_volRslts.getRowPosition(), 'wrkEndHh');
          gr_volRslts.focus();
          return;
        }
        if (endHh.slice(2, 2) > "59") {
          await $c.gus.cfAlertMsg($p, MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
          gr_volRslts.setFocusedCell(ds_volRslts.getRowPosition(), 'wrkEndHh');
          gr_volRslts.focus();
          return;
        }
        if (shift == "M") {
          if (stHh > endHh && endHh > '0700') {
            await $c.gus.cfAlertMsg($p, "야간/심야의 작업종료시간은 07시 이전이어야 합니다.");
            gr_volRslts.setFocusedCell(ds_volRslts.getRowPosition(), 'wrkEndHh');
            gr_volRslts.focus();
            return;
          }
        } else {
          //중부지사(3AA), 동해지사(2AA) 일 경우, 심야 shift를 사용하지 않음 
          //심야를 사용하는 지사가 있기에 그대로 놔두고 두 지사만 제외
          if (lobranCd == '2AA' || lobranCd == '3AA') {} else {
            let afterDateVal = await $c.gus.cfIsAfterDate($p, stHh, endHh);
            if (!afterDateVal) {
              await $c.gus.cfAlertMsg($p, MSG_CM_ERR_058); // 시작시간이 종료시간 이전이어야 합니다.
              gr_volRslts.setFocusedCell(ds_volRslts.getRowPosition(), 'wrkStHh');
              gr_volRslts.focus();
              return;
            }
          }
        }
      }
    }
    if (ds_shiftingRslts.getModifiedIndex().length > 0) {
      let retVal = await $c.gus.cfValidate($p, [gr_shiftingRslts], null, true);
      if (!retVal) return;
    }
    let saveVal = await $c.win.confirm($p, MSG_CM_CRM_001);
    if (saveVal) {
      await scwin.submitExcute(sbm_save);
    }
  } else {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["물량실적"]); // @은(는) 변경된 사항이 없습니다
  }
};

