//-------------------------------------------------------------------------
// 코드를 이름으로 전환(수입,수출)
//-------------------------------------------------------------------------  
scwin.f_GridIOCheck3 = async function () {
  for (var idx = 0; idx < ds_main1.getTotalRow(); idx++) {
    if (ds_main1.getCellData(idx, "impExpClsCd") == "I") {
      ds_main1.setCellData(idx, 'impExpClsCd', "수입");
    } else if (ds_main1.getCellData(idx, "impExpClsCd") == "O") {
      ds_main1.setCellData(idx, 'impExpClsCd', "수출");
    }
  }
};
scwin.f_AddRow = function (grid) {
  let impRepKcg = ds_main1.getCellData(ds_main1.rowPosition, "impKcg");
  let expRepKcg = ds_main1.getCellData(ds_main1.rowPosition, "expKcg");
  let volRow = ds_volRslts.getTotalRow();
  let shiftRow = ds_shiftingRslts.getTotalRow();
  let impExpClsCd = ds_volRslts.getCellData(volRow - 2, "impExpClsCd");
  let holdNo = ds_volRslts.getCellData(volRow - 2, "holdNo");
  switch (grid) {
    case '1':
      ds_volRslts.insertRow();
      ds_volRslts.setCellData(volRow, "holdNo", holdNo); //hold No
      //수입대표화종이 null일 경우
      if ($c.gus.cfIsNull($p, impRepKcg) && impExpClsCd == "O") {
        ds_volRslts.setCellData(volRow, 'impExpClsCd', "O"); //수출입코드
        ds_volRslts.setCellData(volRow, "commNm", expRepKcg); //수입대표화종명
      }
      //수출대표화종이 null일 경우
      if ($c.gus.cfIsNull($p, expRepKcg) && impExpClsCd == "I") {
        ds_volRslts.setCellData(volRow, 'impExpClsCd', "I"); //수출입코드
        ds_volRslts.setCellData(volRow, "commNm", impRepKcg); //수출대표화종명
      }
      gr_volRslts.setFocusedCell(volRow, "completeProcYn", false);
      break;
    case '2':
      ds_shiftingRslts.insertRow();
      ds_shiftingRslts.setRowPosition(gr_shiftingRslts.getTotalRow() - 1);
      let shiftPos = ds_shiftingRslts.getRowPosition();
      let volRsltsVal = ds_volRslts.getCellData(ds_volRslts.getRowPosition(), "wrkIndictNo");
      ds_shiftingRslts.setCellData(shiftPos, "wrkIndictNo", volRsltsVal);
      ds_shiftingRslts.setCellData(shiftPos, "holdNo", shiftPos + 1);
      if (scwin.lobranCd.substring(0, 2) == "6A") {
        if (scwin.importVssl == "T") {
          ds_shiftingRslts.setCellData(shiftPos, "impExpClsCd", "I");
        } else {
          if (scwin.exportVssl == "T") {
            ds_shiftingRslts.setCellData(shiftPos, "impExpClsCd", "O");
          }
        }
        ds_shiftingRslts.setCellData(shiftPos, "commCd", "30000000");
        ds_shiftingRslts.setCellData(shiftPos, "commNm", "일반화물");
      }
      break;
  }
};
scwin.f_deleteRow = function (grid) {
  let deleteIdx;
  let rowIndex;
  let rowStatus;
  switch (grid) {
    case '1':
      $c.data.deleteRow($p, 'gr_volRslts');
      break;
    case '2':
      rowIndex = gr_shiftingRslts.getFocusedRowIndex();
      rowStatus = ds_shiftingRslts.getRowStatusValue(rowIndex);
      if (rowStatus == 3) {
        // 2 -> 3
        ds_shiftingRslts.deleteRow(rowIndex);
        ds_shiftingRslts.removeRow(rowIndex);
      } else {
        ds_shiftingRslts.deleteRow(rowIndex);
      }
      break;
  }
};

