scwin.f_openCommPopUpGrid = async function (gubun, row, pClose) {
  // 선언부
  var rtnList; // 공통POP-UP -> 요청화면 
  var pCode = "";
  var pName = "";
  if (gubun == 1) {
    // 품명 코드팝업			
    pCode = "";
    pName = ds_volRslts.getCellData(row, "commNm"); // 품명
  } else if (gubun == 2) {
    pCode = ds_volRslts.getCellData(row, "commCd");
    pName = ""; // 품명
  }
  await udc_PopUpGrid.cfCommonPopUpAsync(async rtnList => {
    // 품명코드       품명
    let row = ds_volRslts.getRowPosition();
    $c.gus.cfSetGridReturnValue($p, rtnList, ds_volRslts, row, "commCd", "commNm");
  } // XML상의 SELECT ID	
  , pCode // 화면에서의 ??? Code Element의	Value
  , pName // 화면에서의 ??? Name Element의	Value
  , pClose // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
  , '3' // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
  , '품목/품명코드,품목/품명,구분' // Title순서	
  , '105,190,70' // 보여주는 각 컬럼들의 폭	
  , '4,5,6,7,8,9,10' // 컬럼중에서 숨기는	컬럼 지정	
  , ",,,A4" // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
  , null // POP-UP뛰을때 원도우의	사용자 정의	폭
  , null // POP-UP뛰을때 우도우의	사용자 정의	높이	
  , null // 윈도우 위치 Y좌표	
  , null // 윈도우 위치 X좌표
  , null // 중복체크여부	("F")
  , "F" // 전체검색허용여부	("F")
  , "품목/품명,품명코드,품명" // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
  );
  return false;
};
